export enum RoomType {
  KITCHEN = 'Kitchen',
  LIVING_ROOM = 'Living Room',
  BEDROOM = 'Bedroom',
  BATHROOM = 'Bathroom',
  EXTERIOR = 'Exterior',
  DINING = 'Dining Room',
  OFFICE = 'Home Office'
}

export enum RenoStyle {
  MODERN = 'Ultra Modern',
  SCANDINAVIAN = 'Scandinavian Minimalist',
  INDUSTRIAL = 'Industrial Loft',
  BOHEMIAN = 'Bohemian Chic',
  TRADITIONAL = 'Modern Traditional',
  MID_CENTURY = 'Mid-Century Modern',
  COASTAL = 'Luxury Coastal'
}

export interface RenovationVision {
  id: string;
  originalImage: string;
  transformedImage: string;
  roomType: RoomType;
  style: RenoStyle;
  estimatedCostRange: string;
  aiDescription: string;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { RoomType, RenoStyle } from "../types";

export const transformImage = async (
  base64Image: string,
  roomType: RoomType,
  style: RenoStyle,
  additionalNotes: string
): Promise<{ imageUrl: string; description: string; costEstimate: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // 1. Transform the image using gemini-2.5-flash-image
  const imagePrompt = `You are a world-class interior designer and architect.
    Task: Transform this ${roomType} into a ${style} masterpiece.
    Guidelines: 
    - Maintain the basic structural layout (window and door positions).
    - Replace all flooring, wall finishes, furniture, and lighting.
    - Style: ${style}. 
    - Additional User Vision: ${additionalNotes}.
    - Ensure the result looks photorealistic and premium.
    - Provide a single clear renovation image.`;

  const imageResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/png',
            data: base64Image.split(',')[1], // Remove prefix if exists
          },
        },
        { text: imagePrompt },
      ],
    },
  });

  let transformedUrl = "";
  for (const part of imageResponse.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      transformedUrl = `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  // 2. Get expert analysis and cost estimation using gemini-3-flash-preview
  const analysisPrompt = `Analyze this ${roomType} renovation from "Before" (original) to "After" (${style} style).
    Provide a concise summary of the changes made and a rough renovation cost estimate for an investor.
    Return the response as a valid JSON object with the following structure:
    {
      "description": "A 2-sentence summary of the transformation",
      "costEstimate": "$XX,XXX - $XX,XXX"
    }`;

  const analysisResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Original details: ${roomType}, Style: ${style}. Additional info: ${additionalNotes}. 
    The renovation has been generated. Provide the requested JSON assessment.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING },
          costEstimate: { type: Type.STRING }
        },
        required: ["description", "costEstimate"]
      }
    }
  });

  const analysis = JSON.parse(analysisResponse.text || '{}');

  return {
    imageUrl: transformedUrl,
    description: analysis.description || "Beautiful renovation in progress.",
    costEstimate: analysis.costEstimate || "Consult local contractors."
  };
};

