import React, { useState, useRef } from 'react';
import { RoomType, RenoStyle, RenovationVision } from '../types';
import { transformImage } from '../services/geminiService';

export const VisionBoard: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [roomType, setRoomType] = useState<RoomType>(RoomType.LIVING_ROOM);
  const [style, setStyle] = useState<RenoStyle>(RenoStyle.MODERN);
  const [notes, setNotes] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [vision, setVision] = useState<RenovationVision | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleGenerate = async () => {
    if (!preview) return;

    setIsProcessing(true);
    try {
      const result = await transformImage(preview, roomType, style, notes);
      const newVision: RenovationVision = {
        id: Math.random().toString(36).substr(2, 9),
        originalImage: preview,
        transformedImage: result.imageUrl,
        roomType,
        style,
        estimatedCostRange: result.costEstimate,
        aiDescription: result.description,
        timestamp: Date.now(),
      };
      setVision(newVision);
    } catch (error) {
      console.error("Renovation failed:", error);
      alert("Something went wrong during the renovation process. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const reset = () => {
    setVision(null);
    setPreview(null);
    setFile(null);
    setNotes('');
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-12">
      {!vision ? (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start">
          {/* Controls */}
          <div className="bg-white p-8 rounded-2xl shadow-xl border border-gray-100 space-y-6">
            <h3 className="text-2xl font-bold text-gray-900 mb-6">Create Your Vision</h3>

            <div className="space-y-4">
              <label className="block text-sm font-medium text-gray-700">1. Select Property Area</label>
              <div className="grid grid-cols-2 gap-2">
                {Object.values(RoomType).map((type) => (
                  <button
                    key={type}
                    onClick={() => setRoomType(type)}
                    className={`py-2 px-4 text-xs font-semibold rounded-lg border transition ${
                      roomType === type ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-gray-50 text-gray-600 border-gray-200 hover:border-indigo-300'
                    }`}
                  >
                    {type}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <label className="block text-sm font-medium text-gray-700">2. Choose Renovation Style</label>
              <select
                value={style}
                onChange={(e) => setStyle(e.target.value as RenoStyle)}
                className="w-full bg-gray-50 border border-gray-200 rounded-lg py-2.5 px-4 focus:ring-2 focus:ring-indigo-500 focus:outline-none"
              >
                {Object.values(RenoStyle).map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>

            <div className="space-y-4">
              <label className="block text-sm font-medium text-gray-700">3. Specific Preferences (Optional)</label>
              <textarea
                placeholder="e.g. Marble countertops, gold accents, more natural light..."
                className="w-full bg-gray-50 border border-gray-200 rounded-lg py-3 px-4 h-24 focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
              />
            </div>

            <div className="pt-4">
              <button
                disabled={!preview || isProcessing}
                onClick={handleGenerate}
                className={`w-full py-4 px-6 rounded-xl text-white font-bold text-lg shadow-lg transition transform active:scale-95 flex items-center justify-center space-x-2 ${
                  !preview || isProcessing ? 'bg-gray-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'
                }`}
              >
                {isProcessing ? (
                  <>
                    <svg className="animate-spin h-5 w-5 mr-3 text-white" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    <span>Envisioning...</span>
                  </>
                ) : (
                  <span>Visualize Renovation</span>
                )}
              </button>
            </div>
          </div>

          {/* Upload Area */}
          <div className="flex flex-col h-full">
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`relative flex-grow border-2 border-dashed rounded-2xl flex flex-col items-center justify-center cursor-pointer transition p-4 ${
                preview ? 'border-transparent' : 'border-gray-300 bg-gray-50 hover:bg-gray-100'
              }`}
            >
              {preview ? (
                <div className="relative w-full h-full rounded-xl overflow-hidden shadow-inner group">
                  <img src={preview} alt="Upload Preview" className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition flex items-center justify-center">
                    <span className="text-white font-semibold">Change Photo</span>
                  </div>
                </div>
              ) : (
                <div className="text-center p-12">
                  <div className="w-16 h-16 bg-white rounded-full shadow-md flex items-center justify-center mx-auto mb-4">
                    <svg className="w-8 h-8 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                    </svg>
                  </div>
                  <p className="text-lg font-medium text-gray-900">Upload Property Photo</p>
                  <p className="text-gray-500 mt-1">Drag and drop or click to browse</p>
                </div>
              )}
              <input 
                type="file" 
                className="hidden" 
                ref={fileInputRef} 
                onChange={handleFileChange}
                accept="image/*"
              />
            </div>
            <p className="text-xs text-gray-400 mt-4 text-center">
              Works best with high-res interior and exterior real estate listing photos.
            </p>
          </div>
        </div>
      ) : (
        <div className="space-y-8 animate-in fade-in duration-700">
          <div className="flex flex-col md:flex-row justify-between items-end gap-4">
            <div>
              <h2 className="text-3xl font-bold text-gray-900">Your Future {vision.roomType}</h2>
              <p className="text-gray-500">Style: <span className="text-indigo-600 font-semibold">{vision.style}</span></p>
            </div>
            <button 
              onClick={reset}
              className="px-6 py-2 border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 transition"
            >
              New Project
            </button>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="space-y-4">
              <p className="text-xs font-bold uppercase tracking-widest text-gray-400">Current State</p>
              <div className="rounded-2xl overflow-hidden shadow-lg aspect-[4/3]">
                <img src={vision.originalImage} alt="Original" className="w-full h-full object-cover grayscale-[20%]" />
              </div>
            </div>
            <div className="space-y-4">
               <p className="text-xs font-bold uppercase tracking-widest text-indigo-500">Proposed Vision</p>
               <div className="rounded-2xl overflow-hidden shadow-2xl ring-4 ring-indigo-500 ring-opacity-20 aspect-[4/3]">
                <img src={vision.transformedImage} alt="Transformed" className="w-full h-full object-cover" />
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 col-span-2">
              <h4 className="text-lg font-bold text-gray-900 mb-2">Designer Assessment</h4>
              <p className="text-gray-600 leading-relaxed">{vision.aiDescription}</p>
            </div>
            <div className="bg-indigo-50 p-6 rounded-2xl border border-indigo-100">
              <h4 className="text-lg font-bold text-indigo-900 mb-2">Est. Renovation Budget</h4>
              <p className="text-3xl font-extrabold text-indigo-600">{vision.estimatedCostRange}</p>
              <p className="text-xs text-indigo-400 mt-2 italic">*Based on regional material and labor averages.</p>
              <button className="mt-4 w-full bg-indigo-600 text-white py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 transition">
                Get Local Quotes
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

