import { GoogleGenAI, Type } from "@google/genai";
import { RoomType, RenoStyle } from "../types";

export const searchListings = async (query: string): Promise<{ text: string; links: { title: string; uri: string }[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Find real estate listings on beandestiny.georgiamls.com based on this search: "${query}". 
    Focus on finding properties that need renovation or have high potential. 
    Provide a summary of the best matches and highlight their unique features.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const links = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.filter(chunk => chunk.web)
    ?.map(chunk => ({
      title: chunk.web!.title || "View Listing",
      uri: chunk.web!.uri
    })) || [];

  return {
    text: response.text || "No specific details found for this search.",
    links
  };
};

export const transformImage = async (
  base64Image: string,
  roomType: RoomType,
  style: RenoStyle,
  additionalNotes: string
): Promise<{ imageUrl: string; description: string; costEstimate: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const imagePrompt = `You are an elite architectural designer for Unveil. 
    Source Context: This property is featured on beandestiny.georgiamls.com.
    Task: Transform this ${roomType} into a ${style} masterpiece.
    Guidelines: 
    - Maintain structural integrity (windows, doors, load-bearing locations).
    - Replace all flooring, wall finishes, furniture, and lighting.
    - Style: ${style}. 
    - Additional User Vision: ${additionalNotes}.
    - Ensure high-fidelity, photorealistic output suitable for real estate marketing.
    - Provide a single clear renovation image.`;

  const imageResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/png',
            data: base64Image.split(',')[1],
          },
        },
        { text: imagePrompt },
      ],
    },
  });

  let transformedUrl = "";
  for (const part of imageResponse.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      transformedUrl = `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  const analysisPrompt = `Analyze this ${roomType} renovation for a property found on beandestiny.georgiamls.com.
    The transformation is from "Before" to "After" (${style} style).
    Provide a concise summary and a rough renovation cost estimate.
    Return as JSON:
    {
      "description": "Summary of transformation",
      "costEstimate": "$XX,XXX - $XX,XXX"
    }`;

  const analysisResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Original details: ${roomType}, Style: ${style}. Additional info: ${additionalNotes}. 
    The renovation has been generated. Provide the requested JSON assessment.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING },
          costEstimate: { type: Type.STRING }
        },
        required: ["description", "costEstimate"]
      }
    }
  });

  const analysis = JSON.parse(analysisResponse.text || '{}');

  return {
    imageUrl: transformedUrl,
    description: analysis.description || "Beautiful renovation in progress.",
    costEstimate: analysis.costEstimate || "Consult local contractors."
  };
};

import React, { useState, useRef } from 'react';
import { RoomType, RenoStyle, RenovationVision } from '../types';
import { transformImage, searchListings } from '../services/geminiService';

