              <div className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100 space-y-8">
                <div className="flex justify-between items-center">
                   <h3 className="text-2xl font-bold text-gray-900">Envision Transformation</h3>
                   <span className="text-[10px] bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full font-bold uppercase tracking-widest">AI Spatial Engine</span>
