import { GoogleGenAI, Type } from "@google/genai";
import { RoomType, RenoStyle } from "../types";

export const searchListings = async (query: string): Promise<{ text: string; links: { title: string; uri: string }[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Find real estate listings in Georgia based on this search: "${query}". 
    Focus on finding properties that need renovation or have high potential. 
    Provide a summary of the best matches and highlight their unique features.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const links = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.filter(chunk => chunk.web)
    ?.map(chunk => ({
      title: chunk.web!.title || "View Listing",
      uri: chunk.web!.uri
    })) || [];

  return {
    text: response.text || "No specific details found for this search.",
    links
  };
};

export const transformImage = async (
  base64Image: string,
  roomType: RoomType,
  style: RenoStyle,
  additionalNotes: string
): Promise<{ imageUrl: string; description: string; costEstimate: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const imagePrompt = `You are an elite architectural designer for Unveil. 
    Source Context: This property is a standard real estate listing.
    Task: Transform this ${roomType} into a ${style} masterpiece.
    Guidelines: 
    - Maintain structural integrity (windows, doors, load-bearing locations).
    - Replace all flooring, wall finishes, furniture, and lighting.
    - Style: ${style}. 
    - Additional User Vision: ${additionalNotes}.
    - Ensure high-fidelity, photorealistic output suitable for real estate marketing.
    - Provide a single clear renovation image.`;

  const imageResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/png',
            data: base64Image.split(',')[1],
          },
        },
        { text: imagePrompt },
      ],
    },
  });

  let transformedUrl = "";
  for (const part of imageResponse.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      transformedUrl = `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  const analysisPrompt = `Analyze this ${roomType} renovation for a residential property.
    The transformation is from "Before" to "After" (${style} style).
    Provide a concise summary and a rough renovation cost estimate.
    Return as JSON:
    {
      "description": "Summary of transformation",
      "costEstimate": "$XX,XXX - $XX,XXX"
    }`;

  const analysisResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Original details: ${roomType}, Style: ${style}. Additional info: ${additionalNotes}. 
    The renovation has been generated. Provide the requested JSON assessment.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING },
          costEstimate: { type: Type.STRING }
        },
        required: ["description", "costEstimate"]
      }
    }
  });

  const analysis = JSON.parse(analysisResponse.text || '{}');

  return {
    imageUrl: transformedUrl,
    description: analysis.description || "Beautiful renovation in progress.",
    costEstimate: analysis.costEstimate || "Consult local contractors."
  };
};

import React, { useState, useRef, useEffect, useImperativeHandle, forwardRef } from 'react';
import { RoomType, RenoStyle, RenovationVision } from '../types';
import { transformImage, searchListings } from '../services/geminiService';

export interface VisionBoardHandle {
  triggerSearch: (query: string) => void;
}

export const VisionBoard = forwardRef<VisionBoardHandle, {}>((props, ref) => {
  const [activeTab, setActiveTab] = useState<'renovate' | 'search'>('renovate');
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<{ text: string; links: { title: string; uri: string }[] } | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [roomType, setRoomType] = useState<RoomType>(RoomType.LIVING_ROOM);
  const [style, setStyle] = useState<RenoStyle>(RenoStyle.MODERN);
  const [notes, setNotes] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [vision, setVision] = useState<RenovationVision | null>(null);
  const [sliderPosition, setSliderPosition] = useState(50);
  const [isDragging, setIsDragging] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const boardSectionRef = useRef<HTMLDivElement>(null);
  const sliderRef = useRef<HTMLDivElement>(null);

  useImperativeHandle(ref, () => ({
    triggerSearch: (query: string) => {
      setSearchQuery(query);
      setActiveTab('search');
      executeSearch(query);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }));

  // Slider dragging logic
  useEffect(() => {
    const handleMove = (clientX: number) => {
      if (!sliderRef.current) return;
      const rect = sliderRef.current.getBoundingClientRect();
      const x = clientX - rect.left;
      const position = (x / rect.width) * 100;
      setSliderPosition(Math.min(Math.max(position, 0), 100));
    };

    const onMouseMove = (e: MouseEvent) => {
      if (isDragging) handleMove(e.clientX);
    };

    const onTouchMove = (e: TouchEvent) => {
      if (isDragging) handleMove(e.touches[0].clientX);
    };

    const stopDragging = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', stopDragging);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', stopDragging);
    }

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', stopDragging);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', stopDragging);
    };
  }, [isDragging]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleGenerate = async () => {
    if (!preview) return;
    setIsProcessing(true);
    try {
      const result = await transformImage(preview, roomType, style, notes);
      const newVision: RenovationVision = {
        id: Math.random().toString(36).substr(2, 9),
        originalImage: preview,
        transformedImage: result.imageUrl,
        roomType,
        style,
        estimatedCostRange: result.costEstimate,
        aiDescription: result.description,
        timestamp: Date.now(),
      };
      setVision(newVision);
      setSliderPosition(50);
    } catch (error) {
      console.error("Renovation failed:", error);
      alert("Something went wrong. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const executeSearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    try {
      const results = await searchListings(query);
      setSearchResults(results);
    } catch (error) {
      console.error("Search failed:", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSearchForm = async (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(searchQuery);
  };

  const handleExport = async () => {
    if (!vision) return;
    setIsExporting(true);
    try {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const imgBefore = new Image();
      const imgAfter = new Image();

      await Promise.all([
        new Promise((r) => { imgBefore.onload = r; imgBefore.src = vision.originalImage; }),
        new Promise((r) => { imgAfter.onload = r; imgAfter.src = vision.transformedImage; })
      ]);

      const width = imgBefore.width + imgAfter.width;
      const height = Math.max(imgBefore.height, imgAfter.height) + 100;

      canvas.width = width;
      canvas.height = height;

      ctx.fillStyle = '#000000';
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(imgBefore, 0, 0);
      ctx.drawImage(imgAfter, imgBefore.width, 0);

      ctx.fillStyle = 'rgba(0,0,0,0.6)';
      ctx.fillRect(20, 20, 160, 50);
      ctx.fillRect(imgBefore.width + 20, 20, 160, 50);

      ctx.fillStyle = '#FFFFFF';
      ctx.font = 'bold 24px Inter, sans-serif';
      ctx.fillText('BEFORE', 50, 53);
      ctx.fillText('AFTER', imgBefore.width + 50, 53);

      ctx.fillStyle = '#111827';
      ctx.fillRect(0, height - 100, width, 100);
      ctx.fillStyle = '#FFFFFF';
      ctx.font = 'bold 32px Inter, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('UNVEIL', width / 2, height - 55);

      ctx.fillStyle = '#6366F1';
      ctx.font = '16px Inter, sans-serif';
      ctx.fillText('VISIONARY REAL ESTATE AI', width / 2, height - 25);

      const link = document.createElement('a');
      link.download = `Unveil-Vision-${vision.id}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();

      const shareText = `Check out this vision for a ${vision.roomType} in ${vision.style} style! Estimated budget: ${vision.estimatedCostRange}. Powered by Unveil.`;
      await navigator.clipboard.writeText(shareText);
      alert("Vision exported as image and project summary copied to clipboard!");
    } catch (err) {
      console.error("Export failed", err);
    } finally {
      setIsExporting(false);
    }
  };

  const reset = () => {
    setVision(null);
    setPreview(null);
    setFile(null);
    setNotes('');
  };

  return (
    <div ref={boardSectionRef} className="max-w-7xl mx-auto px-4 py-12 scroll-mt-24">
      <div className="flex justify-center mb-12">
        <div className="bg-gray-100 p-1 rounded-2xl inline-flex shadow-inner">
          <button
            onClick={() => setActiveTab('renovate')}
            className={`px-8 py-2.5 rounded-xl text-sm font-bold tracking-tight transition-all ${
              activeTab === 'renovate' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            Renovate & Envision
          </button>
          <button
            onClick={() => setActiveTab('search')}
            className={`px-8 py-2.5 rounded-xl text-sm font-bold tracking-tight transition-all ${
              activeTab === 'search' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            Find Listings
          </button>
        </div>
      </div>

      {activeTab === 'search' ? (
        <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100">
            <h3 className="text-2xl font-bold text-gray-900 mb-2">Search Regional Listings</h3>
            <p className="text-gray-500 mb-8 font-light text-sm">Find the perfect property to transform. Our AI targets current market inventory.</p>
            <form onSubmit={handleSearchForm} className="flex gap-4">
              <input
                type="text"
                placeholder="e.g. 3 bedroom homes in Buckhead under $500k needing TLC..."
                className="flex-grow bg-gray-50 border border-gray-200 rounded-2xl py-4 px-6 focus:ring-2 focus:ring-indigo-500 focus:outline-none text-lg"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button
                type="submit"
                disabled={isSearching}
                className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 disabled:opacity-50"
              >
                {isSearching ? 'Searching...' : 'Find Properties'}
              </button>
            </form>
          </div>

          {searchResults && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
