    visionBoardRef.current?.triggerSearch(query);
  };

  const handleTabChange = (tab: 'renovate' | 'search' | 'contractors' | 'saved') => {
    setActiveTab(tab);
    // Smooth scroll to content
    const boardElement = document.getElementById('vision-board-section');
    if (boardElement) {
      boardElement.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <Layout onTabChange={handleTabChange} activeTab={activeTab}>
      <RenovationHero onSearch={handleSearch} />
      <div id="vision-board-section" className="bg-white">
        <VisionBoard 
          ref={visionBoardRef} 
          activeTab={activeTab} 
          onTabChange={handleTabChange} 
        />
      </div>

      <section className="py-24 bg-gray-50 border-t border-gray-100">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <h2 className="text-4xl font-bold text-gray-900 mb-16 tracking-tight">The Investor's Edge</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-16">
            <div className="space-y-6">
              <div className="w-14 h-14 bg-white rounded-2xl shadow-md flex items-center justify-center mx-auto text-indigo-600 font-bold text-2xl border border-gray-100">1</div>
              <h4 className="font-bold text-xl tracking-tight">Reveal Equity</h4>
              <p className="text-gray-500 font-light leading-relaxed">Identify undervalued properties and visualize the strategic renovations that drive maximum appreciation.</p>
            </div>
            <div className="space-y-6">
              <div className="w-14 h-14 bg-white rounded-2xl shadow-md flex items-center justify-center mx-auto text-indigo-600 font-bold text-2xl border border-gray-100">2</div>
              <h4 className="font-bold text-xl tracking-tight">Precision Estimates</h4>
              <p className="text-gray-500 font-light leading-relaxed">Generate instant, localized renovation budgets to validate your pro-forma before making an offer.</p>
            </div>
            <div className="space-y-6">
              <div className="w-14 h-14 bg-white rounded-2xl shadow-md flex items-center justify-center mx-auto text-indigo-600 font-bold text-2xl border border-gray-100">3</div>
              <h4 className="font-bold text-xl tracking-tight">Accelerate Diligence</h4>
              <p className="text-gray-500 font-light leading-relaxed">Skip the contractor site-walk and gain a competitive vision in seconds with our industry-leading spatial engine.</p>
            </div>
          </div>
        </div>
      </section>
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect, useImperativeHandle, forwardRef } from 'react';
import { RoomType, RenoStyle, RenovationVision } from '../types';
import { transformImage, searchListings } from '../services/geminiService';

export interface VisionBoardHandle {
  triggerSearch: (query: string) => void;
  setTab: (tab: 'renovate' | 'search' | 'contractors' | 'saved') => void;
}

const MOCK_CONTRACTORS = [
  { id: 1, name: "Peach State Renovations", rating: 4.9, specialty: "Whole House", location: "Atlanta, GA", image: "https://images.unsplash.com/photo-1581094794329-c8112a89af12?auto=format&fit=crop&q=80&w=400" },
  { id: 2, name: "Elite Kitchen & Bath", rating: 4.8, specialty: "Kitchens", location: "Alpharetta, GA", image: "https://images.unsplash.com/photo-1556911223-e2f036ae6aef?auto=format&fit=crop&q=80&w=400" },
  { id: 3, name: "Savannah Heritage Builders", rating: 5.0, specialty: "Historic Restoration", location: "Savannah, GA", image: "https://images.unsplash.com/photo-1503387762-592dea58ef23?auto=format&fit=crop&q=80&w=400" },
  { id: 4, name: "Modern Loft Specialists", rating: 4.7, specialty: "Industrial Design", location: "Midtown Atlanta, GA", image: "https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=400" },
];

export const VisionBoard = forwardRef<VisionBoardHandle, { activeTab: string; onTabChange: (tab: any) => void }>((props, ref) => {
  const { activeTab, onTabChange } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<{ text: string } | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [roomType, setRoomType] = useState<RoomType>(RoomType.LIVING_ROOM);
  const [style, setStyle] = useState<RenoStyle>(RenoStyle.MODERN);
  const [notes, setNotes] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [vision, setVision] = useState<RenovationVision | null>(null);
  const [savedVisions, setSavedVisions] = useState<RenovationVision[]>([]);
  const [sliderPosition, setSliderPosition] = useState(50);
  const [isDragging, setIsDragging] = useState(false);

  // Contractor Filter State
  const [contractorSpecialty, setContractorSpecialty] = useState('All Specialties');
  const [contractorLocation, setContractorLocation] = useState('All Locations');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const boardSectionRef = useRef<HTMLDivElement>(null);
  const sliderRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('unveil_saved_visions');
    if (saved) setSavedVisions(JSON.parse(saved));
  }, []);

  useImperativeHandle(ref, () => ({
    triggerSearch: (query: string) => {
      setSearchQuery(query);
      onTabChange('search');
      executeSearch(query);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    },
    setTab: (tab) => {
      onTabChange(tab);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }));

  // Slider dragging logic
  useEffect(() => {
    const handleMove = (clientX: number) => {
      if (!sliderRef.current) return;
      const rect = sliderRef.current.getBoundingClientRect();
      const x = clientX - rect.left;
      const position = (x / rect.width) * 100;
      setSliderPosition(Math.min(Math.max(position, 0), 100));
    };

    const onMouseMove = (e: MouseEvent) => {
      if (isDragging) handleMove(e.clientX);
    };

    const onTouchMove = (e: TouchEvent) => {
      if (isDragging) handleMove(e.touches[0].clientX);
    };

    const stopDragging = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', stopDragging);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', stopDragging);
    }

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', stopDragging);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', stopDragging);
    };
  }, [isDragging]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleGenerate = async () => {
    if (!preview) return;
    setIsProcessing(true);
    try {
      const result = await transformImage(preview, roomType, style, notes);
      const newVision: RenovationVision = {
        id: Math.random().toString(36).substr(2, 9),
        originalImage: preview,
        transformedImage: result.imageUrl,
        roomType,
        style,
        estimatedCostRange: result.costEstimate,
        aiDescription: result.description,
        timestamp: Date.now(),
      };
      setVision(newVision);
      setSliderPosition(50);

      const updatedSaved = [newVision, ...savedVisions].slice(0, 20);
      setSavedVisions(updatedSaved);
      localStorage.setItem('unveil_saved_visions', JSON.stringify(updatedSaved));
    } catch (error) {
      console.error("Renovation failed:", error);
      alert("Something went wrong. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const executeSearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    try {
      const results = await searchListings(query);
      setSearchResults(results);
    } catch (error) {
      console.error("Search failed:", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSearchForm = async (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(searchQuery);
  };

  const handleExport = async () => {
    if (!vision) return;
    setIsExporting(true);
    try {
      const shareText = `Check out this vision for a ${vision.roomType} in ${vision.style} style! Estimated budget: ${vision.estimatedCostRange}. Powered by Unveil.`;
      await navigator.clipboard.writeText(shareText);
      alert("Vision summary copied to clipboard!");
    } catch (err) {
      console.error("Export failed", err);
    } finally {
      setIsExporting(false);
    }
  };

  const reset = () => {
    setVision(null);
    setPreview(null);
    setFile(null);
    setNotes('');
  };

  // Get filter options from data
  const specialties = ['All Specialties', ...new Set(MOCK_CONTRACTORS.map(c => c.specialty))];
  const locations = ['All Locations', ...new Set(MOCK_CONTRACTORS.map(c => c.location))];

  const filteredContractors = MOCK_CONTRACTORS.filter(c => {
    const specialtyMatch = contractorSpecialty === 'All Specialties' || c.specialty === contractorSpecialty;
    const locationMatch = contractorLocation === 'All Locations' || c.location === contractorLocation;
    return specialtyMatch && locationMatch;
  });

  return (
    <div ref={boardSectionRef} className="max-w-7xl mx-auto px-4 py-12 scroll-mt-24">
      {/* Mobile-friendly Tab Switcher */}
      <div className="flex justify-center mb-12 overflow-x-auto pb-4 px-2">
        <div className="bg-gray-100 p-1 rounded-2xl inline-flex shadow-inner whitespace-nowrap">
          {['renovate', 'search', 'contractors', 'saved'].map((tab) => (
            <button
              key={tab}
              onClick={() => onTabChange(tab as any)}
              className={`px-6 py-2.5 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all ${
                activeTab === tab ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              {tab === 'renovate' ? 'Vision' : tab === 'search' ? 'Listings' : tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'search' ? (
        <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100">
            <h3 className="text-2xl font-bold text-gray-900 mb-2">Georgia Market Search</h3>
            <p className="text-gray-500 mb-8 font-light text-sm">Targeted analysis from official GA MLS inventory. Our AI identifies potential.</p>
            <form onSubmit={handleSearchForm} className="flex gap-4">
              <input
                type="text"
                placeholder="e.g. Buckhead fixer-uppers under $600k..."
                className="flex-grow bg-gray-50 border border-gray-200 rounded-2xl py-4 px-6 focus:ring-2 focus:ring-indigo-500 focus:outline-none text-lg text-gray-900 placeholder-gray-400"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button
                type="submit"
                disabled={isSearching}
                className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 disabled:opacity-50"
              >
                {isSearching ? 'Analyzing GA MLS...' : 'Find Potential'}
              </button>
            </form>
          </div>

          {searchResults && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-xl border border-gray-100">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                  <div>
                    <h4 className="font-bold text-gray-900 text-2xl tracking-tight">GA MLS Intelligence Report</h4>
                    <p className="text-gray-400 text-sm mt-1 uppercase tracking-widest font-bold">Search Query: {searchQuery}</p>
                  </div>
                  <a 
                    href="https://beandestiny.georgiamls.com/idxsearch/" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="inline-flex items-center justify-center px-6 py-3 bg-indigo-600 text-white rounded-2xl text-sm font-bold uppercase tracking-widest hover:bg-indigo-700 transition shadow-lg shadow-indigo-100"
                  >
                    Browse GA MLS Results
                    <svg className="w-4 h-4 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                    </svg>
                  </a>
                </div>
                <div className="prose prose-indigo text-gray-700 max-w-none">
                  <p className="whitespace-pre-wrap font-light leading-relaxed text-lg">{searchResults.text}</p>
                </div>
              </div>
            </div>
          )}
        </div>
      ) : activeTab === 'contractors' ? (
        <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
          <div className="text-center mb-12">
            <h3 className="text-4xl font-bold text-gray-900 mb-4 tracking-tight">Georgia Certified Contractors</h3>
            <p className="text-gray-500 font-light max-w-2xl mx-auto">Vetted specialists ready to turn your Unveil vision into reality. Filtered by your project requirements.</p>
          </div>

          {/* Filtering UI */}
          <div className="flex flex-col md:flex-row justify-center items-center gap-4 mb-16">
            <div className="relative w-full md:w-64">
              <select
                value={contractorSpecialty}
                onChange={(e) => setContractorSpecialty(e.target.value)}
                className="w-full bg-white border border-gray-200 rounded-2xl py-3 px-5 focus:ring-2 focus:ring-indigo-500 focus:outline-none font-semibold text-xs text-gray-600 uppercase tracking-widest appearance-none shadow-sm"
              >
                {specialties.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
              </div>
            </div>

            <div className="relative w-full md:w-64">
              <select
                value={contractorLocation}
                onChange={(e) => setContractorLocation(e.target.value)}
                className="w-full bg-white border border-gray-200 rounded-2xl py-3 px-5 focus:ring-2 focus:ring-indigo-500 focus:outline-none font-semibold text-xs text-gray-600 uppercase tracking-widest appearance-none shadow-sm"
              >
                {locations.map(l => <option key={l} value={l}>{l}</option>)}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
              </div>
            </div>

            {(contractorSpecialty !== 'All Specialties' || contractorLocation !== 'All Locations') && (
              <button 
                onClick={() => { setContractorSpecialty('All Specialties'); setContractorLocation('All Locations'); }}
                className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest hover:text-indigo-700 transition"
              >
                Clear Filters
              </button>
            )}
          </div>

          {filteredContractors.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
              {filteredContractors.map((c) => (
                <div key={c.id} className="bg-white rounded-3xl shadow-xl overflow-hidden border border-gray-100 group hover:scale-[1.02] transition-all">
                  <div className="h-48 relative">
                    <img src={c.image} alt={c.name} className="w-full h-full object-cover" />
                    <div className="absolute top-4 right-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-[10px] font-bold text-indigo-600 shadow-sm uppercase tracking-widest">
                      ★ {c.rating}
                    </div>
                  </div>
                  <div className="p-6">
                    <span className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-1 block">{c.specialty}</span>
                    <h4 className="text-xl font-bold text-gray-900 mb-1">{c.name}</h4>
                    <p className="text-sm text-gray-500 mb-6 flex items-center">
                      <svg className="w-4 h-4 mr-1 text-gray-300" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" />
                      </svg>
                      {c.location}
                    </p>
                    <button className="w-full py-3 bg-gray-50 group-hover:bg-indigo-600 group-hover:text-white text-gray-900 font-bold rounded-xl text-xs uppercase tracking-widest transition-all">
                      Request Quote
                    </button>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-20 bg-gray-50 rounded-[3rem] border border-gray-200">
               <p className="text-xl font-bold text-gray-900">No contractors found matching those filters</p>
               <p className="text-gray-400 mt-2">Try adjusting your specialty or location preferences.</p>
            </div>
          )}
        </div>
      ) : activeTab === 'saved' ? (
        <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
          <div className="flex justify-between items-end mb-12">
             <h3 className="text-4xl font-bold text-gray-900 tracking-tight">Vision Gallery</h3>
             <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{savedVisions.length} Saved Projects</span>
          </div>
          {savedVisions.length === 0 ? (
            <div className="text-center py-32 bg-gray-50 rounded-[3rem] border-2 border-dashed border-gray-200">
              <div className="w-20 h-20 bg-white rounded-3xl shadow-lg flex items-center justify-center mx-auto mb-6 text-indigo-200">
                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                </svg>
              </div>
              <p className="text-xl font-bold text-gray-900 mb-2">No Saved Visions Yet</p>
              <p className="text-gray-400 font-light max-w-sm mx-auto mb-8">Start by uploading a property photo and unveiling its potential in the Vision tab.</p>
              <button 
                onClick={() => onTabChange('renovate')}
                className="px-8 py-3 bg-indigo-600 text-white rounded-full font-bold text-xs uppercase tracking-widest shadow-xl shadow-indigo-100"
              >
                Create First Vision
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {savedVisions.map((v) => (
                <div 
                  key={v.id} 
                  className="bg-white rounded-3xl shadow-xl overflow-hidden border border-gray-100 group cursor-pointer"
                  onClick={() => { setVision(v); onTabChange('renovate'); }}
                >
                  <div className="h-56 relative">
                    <img src={v.transformedImage} alt={v.style} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition flex items-center justify-center">
                       <span className="text-white font-bold text-xs uppercase tracking-[0.2em] border-2 border-white px-4 py-2 rounded-lg">View Details</span>
                    </div>
                  </div>
                  <div className="p-6">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest block mb-1">{v.roomType}</span>
                        <h4 className="text-lg font-bold text-gray-900">{v.style}</h4>
                      </div>
                      <span className="text-xs font-bold text-gray-400">{v.estimatedCostRange}</span>
                    </div>
                    <p className="text-xs text-gray-400 line-clamp-2 italic">"{v.aiDescription}"</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      ) : (
        <div className="max-w-6xl mx-auto">
          {!vision ? (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start animate-in fade-in duration-500">
              <div className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100 space-y-8">
                <div className="flex justify-between items-center">
                   <h3 className="text-2xl font-bold text-gray-900">Envision Transformation</h3>
                   <span className="text-[10px] bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full font-bold uppercase tracking-widest">AI Spatial Engine</span>
                </div>

                <div className="space-y-4">
                  <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest">1. Property Area</label>
                  <div className="grid grid-cols-2 gap-2">
                    {Object.values(RoomType).map((type) => (
                      <button
                        key={type}
                        onClick={() => setRoomType(type)}
                        className={`py-2 px-4 text-xs font-semibold rounded-xl border transition-all ${
                          roomType === type ? 'bg-indigo-600 text-white border-indigo-600 shadow-md shadow-indigo-100 scale-[1.02]' : 'bg-gray-50 text-gray-600 border-gray-200 hover:border-indigo-300'
                        }`}
                      >
                        {type}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4">
                  <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest">2. Design Aesthetic</label>
                  <select
                    value={style}
                    onChange={(e) => setStyle(e.target.value as RenoStyle)}
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl py-3 px-4 focus:ring-2 focus:ring-indigo-500 focus:outline-none font-medium text-gray-700"
                  >
                    {Object.values(RenoStyle).map((s) => (
                      <option key={s} value={s}>{s}</option>
                    ))}
                  </select>
                </div>

                <div className="space-y-4">
                  <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest">3. Vision Notes (Optional)</label>
                  <textarea
                    placeholder="Describe specific finishes or features seen in GA MLS photos..."
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl py-3 px-4 h-28 focus:ring-2 focus:ring-indigo-500 focus:outline-none font-light text-gray-900 placeholder-gray-400"
                    value={notes}
                    onChange={(e) => setNotes(e.target.value)}
                  />
                </div>

                <div className="pt-2">
                  <button
                    disabled={!preview || isProcessing}
                    onClick={handleGenerate}
                    className={`w-full py-5 px-6 rounded-2xl text-white font-bold text-lg shadow-xl transition-all transform active:scale-95 flex items-center justify-center space-x-2 ${
                      !preview || isProcessing ? 'bg-gray-300 cursor-not-allowed shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'
                    }`}
                  >
                    {isProcessing ? (
                      <>
                        <svg className="animate-spin h-6 w-6 mr-3 text-white" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span className="tracking-tight">Unveiling Potential...</span>
