export const VisionBoard = forwardRef<VisionBoardHandle, { activeTab: string; onTabChange: (tab: any) => void }>((props, ref) => {
  const { activeTab, onTabChange } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<{ text: string } | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [roomType, setRoomType] = useState<RoomType>(RoomType.LIVING_ROOM);
  const [style, setStyle] = useState<RenoStyle>(RenoStyle.MODERN);
  const [notes, setNotes] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [vision, setVision] = useState<RenovationVision | null>(null);
  const [savedVisions, setSavedVisions] = useState<RenovationVision[]>([]);
  const [sliderPosition, setSliderPosition] = useState(50);
  const [isDragging, setIsDragging] = useState(false);

  // Contractor Search State
  const [contractorSpecialty, setContractorSpecialty] = useState('General Contractor');
  const [contractorLocation, setContractorLocation] = useState('Atlanta, GA');
  const [contractors, setContractors] = useState<Contractor[]>([]);
  const [isSearchingContractors, setIsSearchingContractors] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const boardSectionRef = useRef<HTMLDivElement>(null);
  const sliderRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('unveil_saved_visions');
    if (saved) setSavedVisions(JSON.parse(saved));
  }, []);

  useImperativeHandle(ref, () => ({
    triggerSearch: (query: string) => {
      setSearchQuery(query);
      onTabChange('search');
      executeSearch(query);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    },
    setTab: (tab) => {
      onTabChange(tab);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }));

  // Auto-search contractors when location or specialty changes (debounced or manual trigger)
  const handleContractorSearch = async () => {
    setIsSearchingContractors(true);
    try {
      const results = await searchContractors(contractorSpecialty, contractorLocation);
      setContractors(results);
    } catch (error) {
      console.error("Contractor search failed", error);
    } finally {
      setIsSearchingContractors(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'contractors' && contractors.length === 0) {
      handleContractorSearch();
    }
  }, [activeTab]);

  // Slider dragging logic
  useEffect(() => {
    const handleMove = (clientX: number) => {
      if (!sliderRef.current) return;
      const rect = sliderRef.current.getBoundingClientRect();
      const x = clientX - rect.left;
      const position = (x / rect.width) * 100;
      setSliderPosition(Math.min(Math.max(position, 0), 100));
    };

    const onMouseMove = (e: MouseEvent) => {
      if (isDragging) handleMove(e.clientX);
    };

    const onTouchMove = (e: TouchEvent) => {
      if (isDragging) handleMove(e.touches[0].clientX);
    };

    const stopDragging = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', stopDragging);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', stopDragging);
    }

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', stopDragging);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', stopDragging);
    };
  }, [isDragging]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleGenerate = async () => {
    if (!preview) return;
    setIsProcessing(true);
    try {
      const result = await transformImage(preview, roomType, style, notes);
      const newVision: RenovationVision = {
        id: Math.random().toString(36).substr(2, 9),
        originalImage: preview,
        transformedImage: result.imageUrl,
        roomType,
        style,
        estimatedCostRange: result.costEstimate,
        aiDescription: result.description,
        timestamp: Date.now(),
      };
      setVision(newVision);
      setSliderPosition(50);

      const updatedSaved = [newVision, ...savedVisions].slice(0, 20);
      setSavedVisions(updatedSaved);
      localStorage.setItem('unveil_saved_visions', JSON.stringify(updatedSaved));
    } catch (error) {
      console.error("Renovation failed:", error);
      alert("Something went wrong. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const executeSearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    try {
      const results = await searchListings(query);
      setSearchResults(results);
    } catch (error) {
      console.error("Search failed:", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSearchForm = async (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(searchQuery);
  };

  const handleExport = async () => {
    if (!vision) return;
    setIsExporting(true);
    try {
      const shareText = `Check out this vision for a ${vision.roomType} in ${vision.style} style! Estimated budget: ${vision.estimatedCostRange}. Powered by Unveil.`;
      await navigator.clipboard.writeText(shareText);
      alert("Vision summary copied to clipboard!");
    } catch (err) {
      console.error("Export failed", err);
    } finally {
      setIsExporting(false);
    }
  };

  const reset = () => {
    setVision(null);
    setPreview(null);
    setFile(null);
    setNotes('');
  };

  return (
    <div ref={boardSectionRef} className="max-w-7xl mx-auto px-4 py-12 scroll-mt-24">
      {/* Mobile-friendly Tab Switcher */}
      <div className="flex justify-center mb-12 overflow-x-auto pb-4 px-2">
        <div className="bg-gray-100 p-1 rounded-2xl inline-flex shadow-inner whitespace-nowrap">
          {['renovate', 'search', 'contractors', 'saved'].map((tab) => (
            <button
              key={tab}
              onClick={() => onTabChange(tab as any)}
              className={`px-6 py-2.5 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all ${
                activeTab === tab ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-400 hover:text-gray-700'
              }`}
            >
              {tab === 'renovate' ? 'Vision' : tab === 'search' ? 'Listings' : tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'search' ? (
        <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100">
            <h3 className="text-2xl font-bold text-gray-900 mb-2">Georgia Market Search</h3>
            <p className="text-gray-500 mb-8 font-light text-sm">Targeted analysis from official GA MLS inventory. Our AI identifies potential.</p>
            <form onSubmit={handleSearchForm} className="flex gap-4">
              <input
                type="text"
                placeholder="e.g. Buckhead fixer-uppers under $600k..."
                className="flex-grow bg-gray-50 border border-gray-200 rounded-2xl py-4 px-6 focus:ring-2 focus:ring-indigo-500 focus:outline-none text-lg text-gray-900 placeholder-gray-400"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button
                type="submit"
                disabled={isSearching}
                className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 disabled:opacity-50"
              >
                {isSearching ? 'Analyzing GA MLS...' : 'Find Potential'}
              </button>
            </form>
          </div>

          {searchResults && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-xl border border-gray-100">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                  <div>
                    <h4 className="font-bold text-gray-900 text-2xl tracking-tight">GA MLS Intelligence Report</h4>
                    <p className="text-gray-400 text-sm mt-1 uppercase tracking-widest font-bold">Search Query: {searchQuery}</p>
                  </div>
                  <a 
                    href="https://beandestiny.georgiamls.com/idxsearch/" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="inline-flex items-center justify-center px-6 py-3 bg-indigo-600 text-white rounded-2xl text-sm font-bold uppercase tracking-widest hover:bg-indigo-700 transition shadow-lg shadow-indigo-100"
                  >
                    Browse GA MLS Results
                    <svg className="w-4 h-4 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                    </svg>
                  </a>
                </div>
                <div className="prose prose-indigo text-gray-700 max-w-none">
                  <p className="whitespace-pre-wrap font-light leading-relaxed text-lg">{searchResults.text}</p>
                </div>
              </div>
            </div>
          )}
        </div>
      ) : activeTab === 'contractors' ? (
        <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
          <div className="text-center mb-12">
            <h3 className="text-4xl font-bold text-gray-900 mb-4 tracking-tight">Live Local Pros</h3>
            <p className="text-gray-500 font-light max-w-2xl mx-auto">Our spatial AI searches real-time data from the web to find top-rated contractors in Georgia for your specific needs.</p>
          </div>

          {/* Filtering UI */}
          <div className="flex flex-col md:flex-row justify-center items-center gap-4 mb-16">
            <div className="relative w-full md:w-64">
              <select
                value={contractorSpecialty}
                onChange={(e) => setContractorSpecialty(e.target.value)}
