              </div>
            </div>

            <button 
              onClick={handleContractorSearch}
              disabled={isSearchingContractors}
              className="bg-indigo-600 text-white px-8 py-3 rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 disabled:opacity-50"
            >
              {isSearchingContractors ? 'Searching Web...' : 'Find Pros'}
            </button>
          </div>

          {isSearchingContractors ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
              {[1, 2, 3, 4].map((i) => (
                <div key={i} className="bg-white rounded-3xl shadow-xl overflow-hidden border border-gray-100 animate-pulse">
