];

export const RenovationHero: React.FC<RenovationHeroProps> = ({ onSearch }) => {
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [filteredSuggestions, setFilteredSuggestions] = useState<string[]>([]);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentImageIndex((prev) => (prev + 1) % ATLANTA_IMAGES.length);
    }, 6000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (searchQuery.length > 1) {
      const filtered = GA_SUGGESTIONS.filter(s => 
        s.toLowerCase().includes(searchQuery.toLowerCase())
      );
      setFilteredSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  }, [searchQuery]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      onSearch(searchQuery);
      setShowSuggestions(false);
    }
  };

  const handleSuggestionClick = (suggestion: string) => {
    setSearchQuery(suggestion);
    onSearch(suggestion);
    setShowSuggestions(false);
  };

  return (
    <div className="relative min-h-[85vh] flex items-center justify-center overflow-hidden bg-emerald-950">
      {/* Background Slideshow */}
      {ATLANTA_IMAGES.map((img, index) => (
        <div
          key={img}
          className={`absolute inset-0 transition-opacity duration-[2000ms] ease-in-out ${
            index === currentImageIndex ? 'opacity-100 scale-105' : 'opacity-0 scale-100'
          }`}
          style={{
            backgroundImage: `url(${img})`,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            transitionProperty: 'opacity, transform',
          }}
        >
          <div className="absolute inset-0 bg-black/60 backdrop-blur-[1px]"></div>
        </div>
      ))}

      {/* Hero Content */}
      <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
        <div className="animate-in fade-in slide-in-from-bottom-8 duration-1000">
          <span className="inline-block px-4 py-1.5 bg-emerald-500/10 backdrop-blur-md text-emerald-400 text-[10px] font-bold uppercase tracking-[0.2em] rounded-full mb-6 border border-emerald-500/30">
            Next-Gen Property Visualization
          </span>
          <h1 className="text-5xl tracking-tight font-extrabold text-white sm:text-6xl md:text-7xl lg:text-8xl drop-shadow-2xl">
            <span className="block">Unveil the Hidden</span>
            <span className="block text-amber-400/90">Value of Georgia</span>
          </h1>
          <p className="mt-8 max-w-2xl mx-auto text-lg text-stone-200 sm:text-xl md:mt-10 font-light leading-relaxed drop-shadow">
            Search any listing on the GA MLS and instantly transform potential into reality with our spatial AI engine. Powered by the Unveil real estate index.
          </p>

          {/* Home Page Search Bar */}
          <div className="mt-12 max-w-3xl mx-auto relative" ref={dropdownRef}>
            <form onSubmit={handleSubmit} className="relative group">
              <div className="absolute -inset-1 bg-gradient-to-r from-emerald-600 to-amber-500 rounded-[2rem] blur opacity-20 group-hover:opacity-40 transition duration-1000 group-hover:duration-200"></div>
              <div className="relative flex items-center bg-white border border-white/20 rounded-[2rem] p-2 shadow-2xl overflow-hidden">
                <div className="pl-6 text-stone-400">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <input
                  type="text"
                  placeholder="Search GA listings (e.g. Buckhead fixer-upper)..."
                  className="flex-grow bg-transparent border-none text-stone-900 placeholder-stone-400 py-4 px-6 focus:ring-0 focus:outline-none text-lg font-normal"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  onFocus={() => searchQuery.length > 1 && setShowSuggestions(true)}
                />
                <button
                  type="submit"
                  className="bg-emerald-800 hover:bg-emerald-700 text-white px-8 py-4 rounded-[1.5rem] font-bold text-sm uppercase tracking-widest transition-all shadow-lg active:scale-95 m-1"
                >
                  Find Listing
                </button>
              </div>
            </form>

            {/* Suggestions Dropdown */}
            {showSuggestions && (
              <div className="absolute top-full left-0 right-0 mt-2 bg-white/95 backdrop-blur-xl border border-stone-100 rounded-[2rem] shadow-2xl z-50 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                <div className="py-4">
                  <div className="px-6 pb-2 text-[10px] font-bold text-stone-400 uppercase tracking-widest">Suggested Search</div>
                  {filteredSuggestions.map((s, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSuggestionClick(s)}
                      className="w-full text-left px-6 py-3 hover:bg-emerald-50 text-stone-700 font-medium transition-colors border-l-4 border-transparent hover:border-emerald-700 flex items-center"
                    >
                      <svg className="w-4 h-4 mr-3 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                      </svg>
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="mt-4 flex justify-center space-x-6 text-[10px] uppercase tracking-widest font-bold text-white/30">
              <span>Atlanta</span>
              <span className="text-emerald-700">•</span>
              <span>Savannah</span>
              <span className="text-emerald-700">•</span>
              <span>Athens</span>
              <span className="text-emerald-700">•</span>
              <span>Alpharetta</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

