  const [savedVisions, setSavedVisions] = useState<RenovationVision[]>([]);
  const [sliderPosition, setSliderPosition] = useState(50);
  const [isDragging, setIsDragging] = useState(false);

  // Contractor Search State
  const [contractorSpecialty, setContractorSpecialty] = useState('General Contractor');
  const [contractorLocation, setContractorLocation] = useState('Atlanta, GA');
  const [contractors, setContractors] = useState<Contractor[]>([]);
  const [isSearchingContractors, setIsSearchingContractors] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const boardSectionRef = useRef<HTMLDivElement>(null);
  const sliderRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('unveil_saved_visions');
    if (saved) setSavedVisions(JSON.parse(saved));
  }, []);

  useImperativeHandle(ref, () => ({
    triggerSearch: (query: string) => {
      setSearchQuery(query);
      onTabChange('search');
      executeSearch(query);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    },
    setTab: (tab) => {
      onTabChange(tab);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }));

  const handleContractorSearch = async () => {
    setIsSearchingContractors(true);
    try {
      const results = await searchContractors(contractorSpecialty, contractorLocation);
      setContractors(results);
    } catch (error) {
      console.error("Contractor search failed", error);
    } finally {
      setIsSearchingContractors(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'contractors' && contractors.length === 0) {
      handleContractorSearch();
    }
  }, [activeTab]);

  useEffect(() => {
    const handleMove = (clientX: number) => {
      if (!sliderRef.current) return;
      const rect = sliderRef.current.getBoundingClientRect();
      const x = clientX - rect.left;
      const position = (x / rect.width) * 100;
      setSliderPosition(Math.min(Math.max(position, 0), 100));
    };

    const onMouseMove = (e: MouseEvent) => {
      if (isDragging) handleMove(e.clientX);
    };

    const onTouchMove = (e: TouchEvent) => {
      if (isDragging) handleMove(e.touches[0].clientX);
    };

    const stopDragging = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', stopDragging);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', stopDragging);
    }

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', stopDragging);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', stopDragging);
    };
  }, [isDragging]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleGenerate = async () => {
    if (!preview) return;
    setIsProcessing(true);
    try {
      const result = await transformImage(preview, roomType, style, notes);
      const newVision: RenovationVision = {
        id: Math.random().toString(36).substr(2, 9),
        originalImage: preview,
        transformedImage: result.imageUrl,
        roomType,
        style,
        estimatedCostRange: result.costEstimate,
        aiDescription: result.description,
        timestamp: Date.now(),
      };
      setVision(newVision);
      setSliderPosition(50);

      const updatedSaved = [newVision, ...savedVisions].slice(0, 20);
      setSavedVisions(updatedSaved);
      localStorage.setItem('unveil_saved_visions', JSON.stringify(updatedSaved));
    } catch (error) {
      console.error("Renovation failed:", error);
      alert("Something went wrong. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const executeSearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    try {
      const results = await searchListings(query);
      setSearchResults(results);
    } catch (error) {
      console.error("Search failed:", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSearchForm = async (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(searchQuery);
  };

  const handleExport = async () => {
    if (!vision) return;
    setIsExporting(true);
    try {
      const shareText = `Check out this vision for a ${vision.roomType} in ${vision.style} style! Estimated budget: ${vision.estimatedCostRange}. Powered by Unveil.`;
      await navigator.clipboard.writeText(shareText);
      alert("Vision summary copied to clipboard!");
    } catch (err) {
      console.error("Export failed", err);
    } finally {
      setIsExporting(false);
    }
  };

  const reset = () => {
    setVision(null);
    setPreview(null);
    setFile(null);
    setNotes('');
  };

  return (
    <div ref={boardSectionRef} className="max-w-7xl mx-auto px-4 py-12 scroll-mt-24">
      {/* Mobile-friendly Tab Switcher */}
      <div className="flex justify-center mb-12 overflow-x-auto pb-4 px-2">
        <div className="bg-stone-100 p-1.5 rounded-[2rem] inline-flex shadow-inner whitespace-nowrap">
          {['renovate', 'search', 'contractors', 'saved'].map((tab) => (
            <button
              key={tab}
              onClick={() => onTabChange(tab as any)}
              className={`px-6 py-2.5 rounded-[1.5rem] text-[10px] font-bold uppercase tracking-widest transition-all ${
                activeTab === tab ? 'bg-white text-emerald-800 shadow-sm' : 'text-stone-500 hover:text-stone-700'
              }`}
            >
              {tab === 'renovate' ? 'Vision' : tab === 'search' ? 'Listings' : tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'search' ? (
        <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-stone-100">
            <h3 className="text-2xl font-bold text-stone-900 mb-2">Georgia Market Search</h3>
            <p className="text-stone-500 mb-8 font-light text-sm">Targeted analysis from official GA MLS inventory. Our AI identifies potential.</p>
            <form onSubmit={handleSearchForm} className="flex gap-4">
              <input
                type="text"
                placeholder="e.g. Buckhead fixer-uppers under $600k..."
                className="flex-grow bg-stone-50 border border-stone-200 rounded-2xl py-4 px-6 focus:ring-2 focus:ring-emerald-700 focus:outline-none text-lg text-stone-900 placeholder-stone-400"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button
                type="submit"
                disabled={isSearching}
                className="bg-emerald-800 text-white px-8 py-4 rounded-2xl font-bold hover:bg-emerald-900 transition shadow-lg shadow-emerald-900/10 disabled:opacity-50"
              >
                {isSearching ? 'Analyzing GA MLS...' : 'Find Potential'}
              </button>
            </form>
          </div>

          {searchResults && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-xl border border-stone-100">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                  <div>
                    <h4 className="font-bold text-stone-900 text-2xl tracking-tight">GA MLS Intelligence Report</h4>
                    <p className="text-stone-400 text-sm mt-1 uppercase tracking-widest font-bold">Search Query: {searchQuery}</p>
                  </div>
                  <a 
                    href="https://beandestiny.georgiamls.com/idxsearch/" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="inline-flex items-center justify-center px-6 py-3 bg-emerald-800 text-white rounded-2xl text-sm font-bold uppercase tracking-widest hover:bg-emerald-900 transition shadow-lg shadow-emerald-900/10"
                  >
                    Browse GA MLS Results
                    <svg className="w-4 h-4 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                    </svg>
                  </a>
                </div>
                <div className="prose prose-emerald text-stone-700 max-w-none">
                  <p className="whitespace-pre-wrap font-light leading-relaxed text-lg">{searchResults.text}</p>
                </div>
              </div>
            </div>
          )}
        </div>
      ) : activeTab === 'contractors' ? (
        <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
          <div className="text-center mb-12">
            <h3 className="text-4xl font-bold text-stone-900 mb-4 tracking-tight">Live Local Pros</h3>
            <p className="text-stone-500 font-light max-w-2xl mx-auto">Our spatial AI searches real-time data from the web to find top-rated contractors in Georgia for your specific needs.</p>
          </div>

          {/* Filtering UI */}
          <div className="flex flex-col md:flex-row justify-center items-center gap-4 mb-16">
            <div className="relative w-full md:w-64">
              <select
                value={contractorSpecialty}
                onChange={(e) => setContractorSpecialty(e.target.value)}
                className="w-full bg-white border border-stone-200 rounded-2xl py-3 px-5 focus:ring-2 focus:ring-emerald-700 focus:outline-none font-semibold text-xs text-stone-600 uppercase tracking-widest appearance-none shadow-sm"
              >
                {SPECIALTIES.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
              </div>
            </div>

            <div className="relative w-full md:w-64">
              <select
                value={contractorLocation}
                onChange={(e) => setContractorLocation(e.target.value)}
                className="w-full bg-white border border-stone-200 rounded-2xl py-3 px-5 focus:ring-2 focus:ring-emerald-700 focus:outline-none font-semibold text-xs text-stone-600 uppercase tracking-widest appearance-none shadow-sm overflow-hidden"
              >
                {GEORGIA_CITIES.map(l => <option key={l} value={l}>{l}</option>)}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
              </div>
            </div>

            <button 
              onClick={handleContractorSearch}
              disabled={isSearchingContractors}
              className="bg-emerald-800 text-white px-8 py-3 rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-900 transition shadow-lg shadow-emerald-900/10 disabled:opacity-50"
            >
              {isSearchingContractors ? 'Searching Web...' : 'Find Pros'}
            </button>
          </div>

          {isSearchingContractors ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
              {[1, 2, 3, 4].map((i) => (
                <div key={i} className="bg-white rounded-3xl shadow-xl overflow-hidden border border-stone-100 animate-pulse">
                  <div className="h-48 bg-stone-100"></div>
                  <div className="p-6 space-y-4">
                    <div className="h-4 bg-stone-100 rounded w-1/2"></div>
                    <div className="h-6 bg-stone-100 rounded w-3/4"></div>
                    <div className="h-4 bg-stone-100 rounded w-full"></div>
                    <div className="h-10 bg-stone-100 rounded"></div>
                  </div>
                </div>
              ))}
            </div>
          ) : contractors.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {contractors.map((c) => (
                <div key={c.id} className="bg-white rounded-3xl shadow-xl overflow-hidden border border-stone-100 group hover:scale-[1.02] transition-all flex flex-col">
                  <div className="h-56 relative">
                    <img src={c.image} alt={c.name} className="w-full h-full object-cover" />
                    <div className="absolute top-4 right-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-[10px] font-bold text-emerald-800 shadow-sm uppercase tracking-widest">
                      ★ {c.rating}
                    </div>
                  </div>
                  <div className="p-8 flex flex-col flex-grow">
                    <div className="mb-4">
                      <span className="text-[10px] font-bold text-amber-500 uppercase tracking-widest mb-1 block">{c.specialty}</span>
                      <h4 className="text-2xl font-bold text-stone-900 mb-1">{c.name}</h4>
                      <p className="text-sm text-stone-500 flex items-center mb-4">
                        <svg className="w-4 h-4 mr-1 text-stone-300" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" />
                        </svg>
                        {c.location}
                      </p>
                    </div>
                    <p className="text-stone-600 font-light text-sm mb-8 leading-relaxed line-clamp-3">
                      {c.description}
                    </p>
                    <div className="mt-auto space-y-3">
                      <button className="w-full py-4 bg-emerald-800 text-white font-bold rounded-2xl text-xs uppercase tracking-widest transition-all shadow-lg shadow-emerald-900/10">
                        Request Vision Review
                      </button>
                      {c.website && (
                        <a 
                          href={c.website} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="block text-center w-full py-4 bg-stone-50 text-stone-600 font-bold rounded-2xl text-[10px] uppercase tracking-widest hover:bg-stone-100 transition-all"
                        >
                          Visit Portfolio
                        </a>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-20 bg-stone-50 rounded-[3rem] border border-stone-200">
               <p className="text-xl font-bold text-stone-900">No contractors found matching those filters</p>
               <p className="text-stone-400 mt-2">Try adjusting your specialty or location preferences and click "Find Pros".</p>
            </div>
          )}
        </div>
      ) : activeTab === 'saved' ? (
        <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
          <div className="flex justify-between items-end mb-12">
             <h3 className="text-4xl font-bold text-stone-900 tracking-tight">Vision Gallery</h3>
             <span className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">{savedVisions.length} Saved Projects</span>
          </div>
          {savedVisions.length === 0 ? (
            <div className="text-center py-32 bg-stone-50 rounded-[3rem] border-2 border-dashed border-stone-200">
              <div className="w-20 h-20 bg-white rounded-3xl shadow-lg flex items-center justify-center mx-auto mb-6 text-emerald-200">
                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                </svg>
              </div>
              <p className="text-xl font-bold text-stone-900 mb-2">No Saved Visions Yet</p>
              <p className="text-stone-400 font-light max-sm mx-auto mb-8">Start by uploading a property photo and unveiling its potential in the Vision tab.</p>
              <button 
                onClick={() => onTabChange('renovate')}
                className="px-8 py-3 bg-emerald-800 text-white rounded-full font-bold text-xs uppercase tracking-widest shadow-xl shadow-emerald-900/10"
              >
                Create First Vision
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {savedVisions.map((v) => (
                <div 
                  key={v.id} 
                  className="bg-white rounded-3xl shadow-xl overflow-hidden border border-stone-100 group cursor-pointer"
                  onClick={() => { setVision(v); onTabChange('renovate'); }}
                >
                  <div className="h-56 relative">
                    <img src={v.transformedImage} alt={v.style} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition flex items-center justify-center">
                       <span className="text-white font-bold text-xs uppercase tracking-[0.2em] border-2 border-white px-4 py-2 rounded-lg">View Details</span>
                    </div>
                  </div>
                  <div className="p-6">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <span className="text-[10px] font-bold text-emerald-700 uppercase tracking-widest block mb-1">{v.roomType}</span>
                        <h4 className="text-lg font-bold text-stone-900">{v.style}</h4>
                      </div>
                      <span className="text-xs font-bold text-stone-400">{v.estimatedCostRange}</span>
                    </div>
                    <p className="text-xs text-stone-400 line-clamp-2 italic">"{v.aiDescription}"</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      ) : (
        <div className="max-w-6xl mx-auto">
          {!vision ? (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start animate-in fade-in duration-500">
              <div className="bg-white p-8 rounded-3xl shadow-xl border border-stone-100 space-y-8">
                <div className="flex justify-between items-center">
                   <h3 className="text-2xl font-bold text-stone-900">Envision Transformation</h3>
                   <span className="text-[10px] bg-emerald-50 text-emerald-800 px-3 py-1 rounded-full font-bold uppercase tracking-widest">AI Spatial Engine</span>
                </div>

                <div className="space-y-4">
                  <label className="block text-xs font-bold text-stone-400 uppercase tracking-widest">1. Property Area</label>
                  <div className="grid grid-cols-2 gap-2">
                    {Object.values(RoomType).map((type) => (
                      <button
                        key={type}
                        onClick={() => setRoomType(type)}
                        className={`py-2 px-4 text-xs font-semibold rounded-xl border transition-all ${
                          roomType === type ? 'bg-emerald-800 text-white border-emerald-800 shadow-md shadow-emerald-900/10 scale-[1.02]' : 'bg-stone-50 text-stone-600 border-stone-200 hover:border-emerald-300'
                        }`}
                      >
                        {type}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4">
                  <label className="block text-xs font-bold text-stone-400 uppercase tracking-widest">2. Design Aesthetic</label>
                  <select
                    value={style}
                    onChange={(e) => setStyle(e.target.value as RenoStyle)}
                    className="w-full bg-stone-50 border border-stone-200 rounded-xl py-3 px-4 focus:ring-2 focus:ring-emerald-700 focus:outline-none font-medium text-stone-700"
                  >
                    {Object.values(RenoStyle).map((s) => (
                      <option key={s} value={s}>{s}</option>
                    ))}
                  </select>
                </div>

                <div className="space-y-4">
                  <label className="block text-xs font-bold text-stone-400 uppercase tracking-widest">3. Vision Notes (Optional)</label>
                  <textarea
                    placeholder="Describe specific finishes or features seen in GA MLS photos..."
                    className="w-full bg-stone-50 border border-stone-200 rounded-xl py-3 px-4 h-28 focus:ring-2 focus:ring-emerald-700 focus:outline-none font-light text-stone-900 placeholder-stone-400"
                    value={notes}
                    onChange={(e) => setNotes(e.target.value)}
                  />
                </div>

                <div className="pt-2">
                  <button
                    disabled={!preview || isProcessing}
                    onClick={handleGenerate}
                    className={`w-full py-5 px-6 rounded-2xl text-white font-bold text-lg shadow-xl transition-all transform active:scale-95 flex items-center justify-center space-x-2 ${
                      !preview || isProcessing ? 'bg-stone-300 cursor-not-allowed shadow-none' : 'bg-emerald-800 hover:bg-emerald-900 shadow-emerald-900/10'
                    }`}
                  >
                    {isProcessing ? (
                      <>
                        <svg className="animate-spin h-6 w-6 mr-3 text-white" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span className="tracking-tight">Unveiling Potential...</span>
                      </>
                    ) : (
                      <span className="tracking-tight">Visualize Your Unveiled Home</span>
                    )}
                  </button>
                </div>
              </div>

              <div className="flex flex-col h-full space-y-4">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`relative flex-grow border-2 border-dashed rounded-3xl flex flex-col items-center justify-center cursor-pointer transition-all p-4 min-h-[400px] ${
                    preview ? 'border-transparent shadow-2xl' : 'border-stone-200 bg-stone-50 hover:bg-stone-100 hover:border-emerald-300'
                  }`}
                >
                  {preview ? (
                    <div className="relative w-full h-full rounded-2xl overflow-hidden shadow-inner group">
                      <img src={preview} alt="Listing Photo" className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition flex items-center justify-center">
                        <span className="text-white font-bold tracking-widest uppercase text-xs">Replace Source Image</span>
                      </div>
                    </div>
                  ) : (
                    <div className="text-center p-12">
                      <div className="w-20 h-20 bg-white rounded-2xl shadow-lg flex items-center justify-center mx-auto mb-6 text-emerald-800">
                        <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                      </div>
                      <p className="text-xl font-bold text-stone-900 tracking-tight text-center">Upload Listing Photo</p>
                      <p className="text-stone-400 mt-2 font-light max-w-xs mx-auto text-center">Import photos from GA MLS listings to unveil their potential future.</p>
                    </div>
                  )}
                  <input 
                    type="file" 
                    className="hidden" 
                    ref={fileInputRef} 
                    onChange={handleFileChange}
                    accept="image/*"
                  />
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
              <div className="flex flex-col md:flex-row justify-between items-end gap-6 border-b border-stone-100 pb-8">
                <div>
                  <span className="text-xs font-bold text-amber-500 uppercase tracking-[0.2em] mb-2 block">Vision Report</span>
                  <h2 className="text-4xl font-extrabold text-stone-900 tracking-tight">Your Future {vision.roomType}</h2>
                  <p className="text-stone-500 mt-1 font-light italic">Refined in {vision.style} aesthetic</p>
                </div>
                <div className="flex gap-4">
                  <button 
                    onClick={handleExport}
                    disabled={isExporting}
                    className="px-6 py-3 bg-white border border-stone-200 rounded-2xl text-[10px] font-bold uppercase tracking-widest text-stone-600 hover:bg-stone-50 transition flex items-center gap-2"
                  >
