            {/* Suggestions Overlay */}
            {showSuggestions && (
              <div className="absolute top-full left-0 right-0 mt-3 bg-white/98 backdrop-blur-2xl border border-stone-100 rounded-[2rem] shadow-2xl z-50 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
