                    <label className="block text-xs font-bold text-stone-400 uppercase tracking-widest">Select Style</label>
                    <select
                      value={style}
                      onChange={(e) => setStyle(e.target.value as RenoStyle)}
                      className="w-full bg-stone-50 border border-stone-200 rounded-xl py-3 px-4 focus:ring-2 focus:ring-emerald-700 focus:outline-none font-medium text-stone-700"
