                            <p className="text-stone-400 mt-2 font-light text-sm">Drop a listing photo here to begin transformation.</p>
                          </div>
                        </div>
                      )}
                      <input 
                        type="file" 
                        className="hidden" 
                        ref={fileInputRef} 
                        onChange={handleFileChange}
                        accept="image/*"
                      />
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
              <div className="flex flex-col md:flex-row justify-between items-end gap-6 border-b border-stone-100 pb-8">
                <div>
                  <span className="text-xs font-bold text-amber-500 uppercase tracking-[0.2em] mb-2 block">Vision Report</span>
                  <h2 className="text-4xl font-extrabold text-stone-900 tracking-tight">Your Future {vision.roomType}</h2>
                </div>
                <div className="flex gap-4">
                  <button onClick={reset} className="px-8 py-3 bg-emerald-800 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-900 transition">
                    New Transformation
                  </button>
                </div>
              </div>

              <div className="max-w-4xl mx-auto">
                <div 
                  ref={sliderRef}
                  className="relative rounded-[2.5rem] overflow-hidden shadow-2xl aspect-[16/9] cursor-ew-resize select-none border-8 border-white group"
                  onMouseDown={() => setIsDragging(true)}
                  onTouchStart={() => setIsDragging(true)}
                >
                  <img src={vision.originalImage} alt="Before" className="absolute inset-0 w-full h-full object-cover grayscale-[15%]" />
                  <div 
                    className="absolute inset-0 w-full h-full overflow-hidden"
                    style={{ clipPath: `inset(0 ${100 - sliderPosition}% 0 0)` }}
                  >
                    <img src={vision.transformedImage} alt="After" className="absolute inset-0 w-full h-full object-cover" />
                  </div>

                  <div 
                    className="absolute inset-y-0 w-0.5 bg-white shadow-[0_0_15px_rgba(0,0,0,0.5)] z-10 transition-transform"
                    style={{ left: `${sliderPosition}%`, transform: `translateX(-50%)` }}
                  >
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-12 h-12 bg-white rounded-full shadow-2xl flex items-center justify-center border-4 border-emerald-800 ring-4 ring-white/20">
                       <svg className="w-6 h-6 text-emerald-800" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M8 12h8M8 12l3-3m-3 3l3 3m8-3l-3-3m3 3l-3 3" />
                       </svg>
                    </div>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <div className="bg-white p-10 rounded-[2.5rem] shadow-xl border border-stone-100 col-span-2">
                  <h4 className="text-2xl font-bold text-stone-900 tracking-tight mb-4">Design Insight</h4>
                  <p className="text-stone-600 leading-relaxed text-lg font-light italic">"{vision.aiDescription}"</p>
                </div>
                <div className="bg-emerald-950 p-10 rounded-[2.5rem] shadow-2xl text-white">
                  <p className="text-xs text-stone-400 mb-2 uppercase tracking-widest font-bold">Estimated Budget</p>
                  <p className="text-5xl font-extrabold text-white tracking-tighter">{vision.estimatedCostRange}</p>
                  <button 
                    onClick={() => onTabChange('contractors')}
                    className="mt-10 w-full bg-emerald-800 text-white py-4 rounded-2xl text-xs font-bold uppercase tracking-widest hover:bg-emerald-700 transition-all"
                  >
                    Find Local Pros
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
});

