const SPECIALTIES = [
  "General Contractor", "Kitchen & Bath", "Roofing", "Landscaping", "Interior Design", 
  "Flooring", "Electrical", "Plumbing", "HVAC", "Historic Restoration", "Smart Home Integration"
];

export const VisionBoard = forwardRef<VisionBoardHandle, { activeTab: string; onTabChange: (tab: any) => void }>((props, ref) => {
  const { activeTab, onTabChange } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<{ text: string } | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  // Listing Filters State
  const [filters, setFilters] = useState<SearchFilters>({
    minPrice: '',
    maxPrice: '',
    beds: '',
    baths: '',
    propertyType: 'Any',
    sortBy: 'Newest'
  });

  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [roomType, setRoomType] = useState<RoomType>(RoomType.LIVING_ROOM);
  const [style, setStyle] = useState<RenoStyle>(RenoStyle.MODERN);
  const [notes, setNotes] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [vision, setVision] = useState<RenovationVision | null>(null);
  const [savedVisions, setSavedVisions] = useState<RenovationVision[]>([]);
  const [sliderPosition, setSliderPosition] = useState(50);
  const [isDragging, setIsDragging] = useState(false);

  const [contractorSpecialty, setContractorSpecialty] = useState('General Contractor');
  const [contractorLocation, setContractorLocation] = useState('Atlanta, GA');
  const [contractors, setContractors] = useState<Contractor[]>([]);
  const [isSearchingContractors, setIsSearchingContractors] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const boardSectionRef = useRef<HTMLDivElement>(null);
  const sliderRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('unveil_saved_visions');
    if (saved) setSavedVisions(JSON.parse(saved));
  }, []);

  useImperativeHandle(ref, () => ({
    triggerSearch: (query: string) => {
      setSearchQuery(query);
      onTabChange('search');
      executeSearch(query, filters);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    },
    setTab: (tab) => {
      onTabChange(tab);
      boardSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }));

  const handleContractorSearch = async () => {
    setIsSearchingContractors(true);
    try {
      const results = await searchContractors(contractorSpecialty, contractorLocation);
      setContractors(results);
    } catch (error) {
      console.error("Contractor search failed", error);
    } finally {
      setIsSearchingContractors(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'contractors' && contractors.length === 0) {
      handleContractorSearch();
    }
  }, [activeTab]);

  useEffect(() => {
    const handleMove = (clientX: number) => {
      if (!sliderRef.current) return;
      const rect = sliderRef.current.getBoundingClientRect();
      const x = clientX - rect.left;
      const position = (x / rect.width) * 100;
      setSliderPosition(Math.min(Math.max(position, 0), 100));
    };

    const onMouseMove = (e: MouseEvent) => {
      if (isDragging) handleMove(e.clientX);
    };

    const onTouchMove = (e: TouchEvent) => {
      if (isDragging) handleMove(e.touches[0].clientX);
    };

    const stopDragging = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', stopDragging);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', stopDragging);
    }

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', stopDragging);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', stopDragging);
    };
  }, [isDragging]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleGenerate = async () => {
    if (!preview) return;
    setIsProcessing(true);
    try {
      const result = await transformImage(preview, roomType, style, notes);
      const newVision: RenovationVision = {
        id: Math.random().toString(36).substr(2, 9),
        originalImage: preview,
        transformedImage: result.imageUrl,
        roomType,
        style,
        estimatedCostRange: result.costEstimate,
        aiDescription: result.description,
        timestamp: Date.now(),
      };
      setVision(newVision);
      setSliderPosition(50);

      const updatedSaved = [newVision, ...savedVisions].slice(0, 20);
      setSavedVisions(updatedSaved);
      localStorage.setItem('unveil_saved_visions', JSON.stringify(updatedSaved));
    } catch (error) {
      console.error("Renovation failed:", error);
      alert("Something went wrong. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const executeSearch = async (query: string, currentFilters: SearchFilters) => {
    if (!query.trim()) return;
    setIsSearching(true);
    try {
      const results = await searchListings(query, currentFilters);
      setSearchResults(results);
    } catch (error) {
      console.error("Search failed:", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSearchForm = async (e: React.FormEvent) => {
    e.preventDefault();
    executeSearch(searchQuery, filters);
  };

  const handleApplyFilters = () => {
    executeSearch(searchQuery, filters);
  };

  const handleShareWithAgent = (id: string) => {
    const updated = savedVisions.map(v => v.id === id ? { ...v, sharedWithAgent: true } : v);
    setSavedVisions(updated);
    localStorage.setItem('unveil_saved_visions', JSON.stringify(updated));
    alert("Vision shared with verified Agents in your market!");
  };

  const reset = () => {
    setVision(null);
    setPreview(null);
    setFile(null);
    setNotes('');
  };

  return (
    <div ref={boardSectionRef} className="max-w-7xl mx-auto px-4 py-12 scroll-mt-24">
      {activeTab === 'search' ? (
        <div className="max-w-6xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="text-center space-y-4 mb-12">
            <h2 className="text-4xl font-extrabold text-stone-900 tracking-tight">Explore Georgia Listings</h2>
            <p className="text-stone-500 max-w-2xl mx-auto font-light">Find properties with high renovation potential across the GA MLS.</p>
          </div>

          <div className="bg-white p-8 md:p-10 rounded-[2.5rem] shadow-xl border border-stone-100 space-y-10">
            {/* Main Search Bar */}
            <form onSubmit={handleSearchForm} className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-emerald-600/20 to-amber-500/20 rounded-[2rem] blur opacity-50 transition duration-1000 group-hover:opacity-100"></div>
               <div className="relative flex items-center bg-stone-50 border border-stone-200 rounded-[1.8rem] p-1.5 focus-within:ring-2 focus-within:ring-emerald-700/30 transition-all">
                <div className="pl-6 text-emerald-800">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <input
                  type="text"
                  placeholder="Address, City, Zip or Market Keyword..."
                  className="flex-grow bg-transparent border-none text-stone-900 placeholder-stone-400 py-4 px-6 focus:ring-0 focus:outline-none text-lg font-medium"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
                <button
                  type="submit"
                  disabled={isSearching}
                  className="bg-emerald-800 hover:bg-emerald-900 text-white px-10 py-4 rounded-[1.4rem] font-bold text-sm uppercase tracking-widest transition-all shadow-lg shadow-emerald-900/10 disabled:opacity-50 flex items-center gap-2"
                >
                  {isSearching ? 'Searching...' : 'Search Listings'}
                </button>
              </div>
            </form>

            {/* Filter Panel */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 pt-4 border-t border-stone-100">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Min Price</label>
                <input 
                  type="text" 
                  placeholder="$0"
                  value={filters.minPrice}
                  onChange={(e) => setFilters({...filters, minPrice: e.target.value})}
                  className="w-full bg-stone-50 border border-stone-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Max Price</label>
                <input 
                  type="text" 
                  placeholder="$1,000,000+"
                  value={filters.maxPrice}
                  onChange={(e) => setFilters({...filters, maxPrice: e.target.value})}
                  className="w-full bg-stone-50 border border-stone-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Beds / Baths</label>
                <div className="flex gap-2">
                  <select 
                    value={filters.beds}
                    onChange={(e) => setFilters({...filters, beds: e.target.value})}
                    className="w-1/2 bg-stone-50 border border-stone-200 rounded-xl px-3 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                  >
                    <option value="">Beds</option>
                    {[1,2,3,4,5].map(n => <option key={n} value={n+"+"}>{n}+</option>)}
                  </select>
                  <select 
                    value={filters.baths}
                    onChange={(e) => setFilters({...filters, baths: e.target.value})}
                    className="w-1/2 bg-stone-50 border border-stone-200 rounded-xl px-3 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                  >
                    <option value="">Baths</option>
                    {[1,2,3,4,5].map(n => <option key={n} value={n+"+"}>{n}+</option>)}
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Property Type</label>
                <select 
                  value={filters.propertyType}
                  onChange={(e) => setFilters({...filters, propertyType: e.target.value})}
                  className="w-full bg-stone-50 border border-stone-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                >
                  <option value="Any">Any Type</option>
                  <option value="Single Family">Single Family</option>
                  <option value="Condo/Townhome">Condo/Townhome</option>
                  <option value="Multi-Family">Multi-Family</option>
                  <option value="Land">Land</option>
                </select>
              </div>
              <div className="flex items-end">
                <button
                  onClick={handleApplyFilters}
                  disabled={isSearching}
                  className="w-full py-3 bg-stone-900 text-white rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-stone-800 transition shadow-md"
                >
                  Apply Filters
                </button>
              </div>
            </div>

            {/* Sorting Row */}
            <div className="flex justify-between items-center pt-2">
              <span className="text-[10px] font-bold text-stone-400 uppercase tracking-[0.2em]">Source: Georgia MLS</span>
              <div className="flex items-center gap-3">
                <span className="text-[10px] font-bold text-stone-500 uppercase tracking-widest">Sort By:</span>
                <select 
                  value={filters.sortBy}
                  onChange={(e) => {
                    const newSort = e.target.value;
                    setFilters({...filters, sortBy: newSort});
                    executeSearch(searchQuery, {...filters, sortBy: newSort});
                  }}
                  className="bg-transparent border-none text-[10px] font-bold text-emerald-800 uppercase tracking-widest focus:ring-0 cursor-pointer"
                >
                  <option value="Newest">Newest</option>
                  <option value="Price Low to High">Price Low to High</option>
                  <option value="Price High to Low">Price High to Low</option>
                  <option value="Investment Score">Investment Score</option>
                </select>
              </div>
            </div>
          </div>

          {searchResults && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-xl border border-stone-100">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                  <div className="space-y-1">
                    <h4 className="font-bold text-stone-900 text-2xl tracking-tight">AI Market Insights</h4>
                    <p className="text-stone-400 text-[10px] uppercase tracking-widest font-bold">Results for "{searchQuery}"</p>
                  </div>
                  <div className="flex gap-4">
                    <button className="flex items-center gap-2 px-6 py-3 bg-emerald-50 text-emerald-800 rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-100 transition">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                      </svg>
                      Save Search
                    </button>
                    <a 
                      href={`https://beandestiny.georgiamls.com/idxsearch/?q=${encodeURIComponent(searchQuery)}`}
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="inline-flex items-center justify-center px-8 py-3 bg-emerald-800 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-900 transition shadow-lg shadow-emerald-900/10"
                    >
                      View All Listings
                      <svg className="w-4 h-4 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                      </svg>
                    </a>
                  </div>
                </div>
                <div className="prose prose-emerald text-stone-700 max-w-none">
                  <p className="whitespace-pre-wrap font-light leading-relaxed text-lg border-l-4 border-emerald-800 pl-8">{searchResults.text}</p>
                </div>
              </div>
            </div>
          )}
        </div>
      ) : activeTab === 'contractors' ? (
        <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
          <div className="text-center mb-12">
            <h3 className="text-4xl font-bold text-stone-900 mb-4 tracking-tight">Verified Local Pros</h3>
            <p className="text-stone-500 font-light max-w-2xl mx-auto">Found the right property? Connect with contractors who can bring your Unveil vision to life.</p>
          </div>

          <div className="flex flex-col md:flex-row justify-center items-center gap-4 mb-16">
            <div className="relative w-full md:w-64">
              <select
                value={contractorSpecialty}
                onChange={(e) => setContractorSpecialty(e.target.value)}
                className="w-full bg-white border border-stone-200 rounded-2xl py-3 px-5 focus:ring-2 focus:ring-emerald-700 focus:outline-none font-semibold text-xs text-stone-600 uppercase tracking-widest appearance-none shadow-sm"
              >
                {SPECIALTIES.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>

            <div className="relative w-full md:w-64">
              <select
                value={contractorLocation}
                onChange={(e) => setContractorLocation(e.target.value)}
                className="w-full bg-white border border-stone-200 rounded-2xl py-3 px-5 focus:ring-2 focus:ring-emerald-700 focus:outline-none font-semibold text-xs text-stone-600 uppercase tracking-widest appearance-none shadow-sm overflow-hidden"
              >
                {GEORGIA_CITIES.map(l => <option key={l} value={l}>{l}</option>)}
              </select>
            </div>

            <button 
              onClick={handleContractorSearch}
              disabled={isSearchingContractors}
              className="bg-emerald-800 text-white px-8 py-3 rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-900 transition shadow-lg shadow-emerald-900/10 disabled:opacity-50"
            >
              {isSearchingContractors ? 'Searching...' : 'Find Pros'}
            </button>
          </div>

          {isSearchingContractors ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
              {[1, 2, 3, 4].map((i) => (
                <div key={i} className="bg-white rounded-3xl shadow-xl overflow-hidden border border-stone-100 animate-pulse">
                  <div className="h-48 bg-stone-100"></div>
                  <div className="p-6 space-y-4">
                    <div className="h-4 bg-stone-100 rounded w-1/2"></div>
                    <div className="h-6 bg-stone-100 rounded w-3/4"></div>
                    <div className="h-4 bg-stone-100 rounded w-full"></div>
                  </div>
                </div>
              ))}
            </div>
          ) : contractors.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {contractors.map((c) => (
                <div key={c.id} className="bg-white rounded-3xl shadow-xl overflow-hidden border border-stone-100 group hover:scale-[1.02] transition-all flex flex-col">
                  <div className="h-56 relative">
                    <img src={c.image} alt={c.name} className="w-full h-full object-cover" />
                    <div className="absolute top-4 right-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-[10px] font-bold text-emerald-800 shadow-sm uppercase tracking-widest">
                      ★ {c.rating}
                    </div>
                  </div>
                  <div className="p-8 flex flex-col flex-grow">
                    <div className="mb-4">
                      <span className="text-[10px] font-bold text-amber-500 uppercase tracking-widest mb-1 block">{c.specialty}</span>
                      <h4 className="text-2xl font-bold text-stone-900 mb-1">{c.name}</h4>
                      <p className="text-sm text-stone-500 flex items-center mb-4">
                        <svg className="w-4 h-4 mr-1 text-stone-300" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" />
                        </svg>
                        {c.location}
                      </p>
                    </div>
                    <p className="text-gray-600 font-light text-sm mb-8 leading-relaxed line-clamp-3">
                      {c.description}
