            <h2 className="text-4xl font-extrabold text-stone-900 tracking-tight">Official Georgia MLS Search</h2>
            <p className="text-stone-500 max-w-2xl mx-auto font-light">Directly query the market for fixer-uppers and investment opportunities.</p>
          </div>

          <div className="bg-white p-8 md:p-10 rounded-[2.5rem] shadow-xl border border-stone-100 space-y-10">
            {/* Primary Search Bar */}
            <form onSubmit={handleListingFormSubmit} className="relative group">
              <div className="absolute -inset-1 bg-gradient-to-r from-emerald-600/20 to-amber-500/20 rounded-[2rem] blur opacity-50"></div>
              <div className="relative flex items-center bg-stone-50 border border-stone-200 rounded-[1.8rem] p-1.5 focus-within:ring-2 focus-within:ring-emerald-700/30 transition-all">
                <div className="pl-6 text-emerald-800">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <input
                  type="text"
                  placeholder="Address, City, Zip or Neighborhood..."
                  className="flex-grow bg-transparent border-none text-stone-900 placeholder-stone-400 py-4 px-6 focus:ring-0 focus:outline-none text-lg font-medium"
                  value={listingQuery}
                  onChange={(e) => setListingQuery(e.target.value)}
                />
                <button
                  type="submit"
                  disabled={isSearchingListings}
                  className="bg-emerald-800 hover:bg-emerald-900 text-white px-10 py-4 rounded-[1.4rem] font-bold text-sm uppercase tracking-widest transition-all shadow-lg shadow-emerald-900/10 disabled:opacity-50 flex items-center gap-2"
                >
                  {isSearchingListings ? 'Searching...' : 'Search Listings'}
                </button>
              </div>
            </form>

            {/* Filter Row */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 pt-4 border-t border-stone-100">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Min Price</label>
                <input 
                  type="text" placeholder="$0"
                  value={listingFilters.minPrice}
                  onChange={(e) => setListingFilters({...listingFilters, minPrice: e.target.value})}
                  className="w-full bg-stone-50 border border-stone-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Max Price</label>
                <input 
                  type="text" placeholder="$1M+"
                  value={listingFilters.maxPrice}
                  onChange={(e) => setListingFilters({...listingFilters, maxPrice: e.target.value})}
                  className="w-full bg-stone-50 border border-stone-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Beds / Baths</label>
                <div className="flex gap-2">
                  <select 
                    value={listingFilters.beds}
                    onChange={(e) => setListingFilters({...listingFilters, beds: e.target.value})}
                    className="w-1/2 bg-stone-50 border border-stone-200 rounded-xl px-3 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                  >
                    <option value="">Beds</option>
                    {[1,2,3,4,5].map(n => <option key={n} value={n+"+"}>{n}+</option>)}
                  </select>
                  <select 
                    value={listingFilters.baths}
                    onChange={(e) => setListingFilters({...listingFilters, baths: e.target.value})}
                    className="w-1/2 bg-stone-50 border border-stone-200 rounded-xl px-3 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                  >
                    <option value="">Baths</option>
                    {[1,2,3,4,5].map(n => <option key={n} value={n+"+"}>{n}+</option>)}
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Property Type</label>
                <select 
                  value={listingFilters.propertyType}
                  onChange={(e) => setListingFilters({...listingFilters, propertyType: e.target.value})}
                  className="w-full bg-stone-50 border border-stone-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-800 outline-none text-sm"
                >
                  <option value="Any">Any Type</option>
                  <option value="Single Family">Single Family</option>
                  <option value="Condo">Condo/Townhome</option>
                  <option value="Multi-Family">Multi-Family</option>
                </select>
              </div>
              <div className="flex items-end">
                <button
                  onClick={handleListingFormSubmit}
                  disabled={isSearchingListings}
                  className="w-full py-3 bg-stone-900 text-white rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-stone-800 transition shadow-md"
                >
                  Apply Filters
                </button>
              </div>
            </div>

            {/* Sorting & Attribution */}
            <div className="flex justify-between items-center pt-2">
              <span className="text-[10px] font-bold text-stone-400 uppercase tracking-[0.2em]">Source: beandestiny.georgiamls.com</span>
              <div className="flex items-center gap-3">
                <span className="text-[10px] font-bold text-stone-500 uppercase tracking-widest">Sort:</span>
                <select 
                  value={listingFilters.sortBy}
                  onChange={(e) => setListingFilters({...listingFilters, sortBy: e.target.value})}
                  className="bg-transparent border-none text-[10px] font-bold text-emerald-800 uppercase tracking-widest focus:ring-0 cursor-pointer"
                >
                  <option value="Newest">Newest</option>
                  <option value="Price Low to High">Price (Low-High)</option>
                  <option value="Price High to Low">Price (High-Low)</option>
                  <option value="Investment Potential">Investment Potential</option>
                </select>
              </div>
            </div>
          </div>

          {/* Listing Results */}
          {listingResults && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="bg-white p-10 md:p-14 rounded-[2.5rem] shadow-xl border border-stone-100">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
                  <div className="space-y-1">
                    <h4 className="font-bold text-stone-900 text-3xl tracking-tight">AI Market Analysis</h4>
                    <p className="text-stone-400 text-[10px] uppercase tracking-widest font-bold">Generated Insight for "{listingQuery}"</p>
                  </div>
                  <a 
                    href={`https://beandestiny.georgiamls.com/idxsearch/?q=${encodeURIComponent(listingQuery)}`}
                    target="_blank" rel="noopener noreferrer"
                    className="inline-flex items-center justify-center px-8 py-4 bg-emerald-800 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-900 transition shadow-lg shadow-emerald-900/10"
                  >
                    View Portals
                    <svg className="w-4 h-4 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                    </svg>
                  </a>
                </div>
                <div className="prose prose-emerald text-stone-700 max-w-none">
                  <p className="whitespace-pre-wrap font-light leading-relaxed text-xl border-l-4 border-emerald-800 pl-8">{listingResults.text}</p>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* 2. CONTRACTORS PAGE TAB */}
      {activeTab === 'contractors' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="text-center space-y-4 mb-12">
            <h2 className="text-4xl font-extrabold text-stone-900 tracking-tight">Find Specialized Professionals</h2>
            <p className="text-stone-500 max-w-2xl mx-auto font-light">From historic restoration to ultra-modern kitchens, connect with the right team for your vision.</p>
          </div>

          <div className="bg-white p-8 md:p-10 rounded-[2.5rem] shadow-xl border border-stone-100 space-y-10">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Trade or Specialty</label>
                <div className="relative group">
                  <div className="absolute -inset-0.5 bg-emerald-600/10 rounded-2xl blur opacity-30 group-hover:opacity-100 transition"></div>
                  <div className="relative flex items-center bg-stone-50 border border-stone-200 rounded-2xl px-4 py-1.5 focus-within:ring-2 focus-within:ring-emerald-700/30 transition-all">
                    <svg className="w-5 h-5 text-emerald-800 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 13.255A23.931 23.931 0 0112 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 00-2-2h-4a2 2 0 00-2 2v2m4 6h.01M5 20h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                    </svg>
                    <select
                      value={contractorType}
                      onChange={(e) => setContractorType(e.target.value)}
