                    className={`w-full py-6 rounded-2xl text-white font-bold text-sm uppercase tracking-widest shadow-xl transition-all active:scale-95 flex items-center justify-center space-x-3 ${
                      !preview || isProcessingVision ? 'bg-stone-300 cursor-not-allowed' : 'bg-emerald-800 hover:bg-emerald-900 shadow-emerald-900/10'
                    }`}
                  >
                    {isProcessingVision ? (
                      <>
                        <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span>Unveiling potential...</span>
                      </>
                    ) : 'Generate Vision'}
                  </button>
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-16 animate-in fade-in slide-in-from-bottom-8 duration-700">
              <div className="flex flex-col md:flex-row justify-between items-end gap-6 border-b border-stone-100 pb-12">
                <div>
                  <span className="text-xs font-bold text-amber-500 uppercase tracking-[0.2em] mb-4 block">Transformation Report</span>
                  <h2 className="text-5xl font-extrabold text-stone-900 tracking-tight">Your Future {vision.roomType}</h2>
                </div>
                <button onClick={resetVision} className="px-10 py-4 bg-emerald-800 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-900 transition shadow-lg">New Transformation</button>
              </div>

              <div className="max-w-5xl mx-auto">
                <div 
                  ref={sliderRef}
                  className="relative rounded-[3rem] overflow-hidden shadow-2xl aspect-[16/9] cursor-ew-resize select-none border-8 border-white group"
                  onMouseDown={() => setIsDragging(true)}
                  onTouchStart={() => setIsDragging(true)}
                >
                  <img src={vision.originalImage} alt="Before" className="absolute inset-0 w-full h-full object-cover grayscale-[10%]" />
                  <div className="absolute inset-0 w-full h-full overflow-hidden" style={{ clipPath: `inset(0 ${100 - sliderPosition}% 0 0)` }}>
                    <img src={vision.transformedImage} alt="After" className="absolute inset-0 w-full h-full object-cover" />
                  </div>
                  <div className="absolute inset-y-0 w-1 bg-white shadow-2xl z-10" style={{ left: `${sliderPosition}%`, transform: `translateX(-50%)` }}>
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-16 h-16 bg-white rounded-full shadow-2xl flex items-center justify-center border-4 border-emerald-800 ring-8 ring-white/20">
                      <svg className="w-8 h-8 text-emerald-800" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M8 12h8M8 12l3-3m-3 3l3 3m8-3l-3-3m3 3l-3 3" />
                      </svg>
                    </div>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
                <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-stone-100 col-span-2 space-y-6">
                  <h4 className="text-2xl font-bold text-stone-900 tracking-tight">AI Vision Insight</h4>
                  <p className="text-stone-600 leading-relaxed text-xl font-light italic">"{vision.aiDescription}"</p>
                </div>
                <div className="bg-emerald-950 p-12 rounded-[3rem] shadow-2xl text-white flex flex-col justify-between">
                  <div>
                    <p className="text-[10px] text-stone-400 mb-4 uppercase tracking-widest font-bold">Estimated Investment</p>
                    <p className="text-6xl font-extrabold text-white tracking-tighter">{vision.estimatedCostRange}</p>
                  </div>
                  <button onClick={() => onTabChange('contractors')} className="mt-12 w-full bg-emerald-800 text-white py-5 rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-700 transition shadow-lg">Find Pros in Georgia</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* 4. SAVED VISIONS PAGE TAB */}
      {activeTab === 'saved' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="flex justify-between items-end mb-12">
            <div>
              <h3 className="text-4xl font-extrabold text-stone-900 tracking-tight">Vision Gallery</h3>
              <p className="text-stone-500 font-light mt-2">Access and manage your portfolio of potential transformations.</p>
            </div>
            <span className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">{savedVisions.length} Saved Projects</span>
          </div>

          {savedVisions.length === 0 ? (
            <div className="text-center py-40 bg-stone-50 rounded-[3rem] border-2 border-dashed border-stone-200">
              <p className="text-2xl font-bold text-stone-900 mb-4">Gallery is Empty</p>
              <button onClick={() => onTabChange('renovate')} className="px-10 py-4 bg-emerald-800 text-white rounded-full font-bold text-[10px] uppercase tracking-widest hover:bg-emerald-900 transition shadow-lg">Start First Vision</button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
              {savedVisions.map((v) => (
                <div key={v.id} className="bg-white rounded-[2.5rem] shadow-xl overflow-hidden border border-stone-100 group flex flex-col hover:scale-[1.02] transition-all">
                  <div className="h-64 relative overflow-hidden cursor-pointer" onClick={() => { setVision(v); onTabChange('renovate'); }}>
                    <img src={v.transformedImage} alt={v.style} className="w-full h-full object-cover transition-transform group-hover:scale-110" />
                    <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                  </div>
                  <div className="p-10 flex-grow flex flex-col">
                    <span className="text-[10px] font-bold text-emerald-700 uppercase tracking-widest block mb-2">{v.roomType}</span>
                    <h4 className="text-2xl font-bold text-stone-900 mb-6">{v.style}</h4>
                    <div className="mt-auto space-y-4">
                      <button className="w-full py-4 bg-emerald-50 text-emerald-800 rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-100 transition">View Full Details</button>
                      <button className="w-full py-4 bg-stone-900 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-stone-800 transition shadow-lg">Connect with Agent</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
});

